  "query": "query { libros { id titulo idAutor } autores { id nombreAutor } }"
}

{
  "query": "query($id: ID!) { libro(id: $id) { id titulo isbn anioPublicacion copiasTotales copiasDisponible idAutor } }",
  "variables": {
    "id": "{{id_libro}}"
  }
}

{
  "query": "query librosYAutores { libros { id titulo idAutor } autores { id nombreAutor } } query libroPorId($id: ID!) { libro(id: $id) { id titulo isbn } } query librosDeAutor($idAutor: ID!) { librosPorAutor(idAutor: $idAutor) { id titulo idAutor } } query autorPorId($id: ID!) { autor(id: $id) { id nombreAutor } }",
  "operationName": "librosYAutores",
  "variables": {
    "idAutor": "{{id_autor}}",
    "id": "{{id_libro}}"
  }
}

